'use strict';

var MAX_ITER = 1075; 
var maxBits = 54; 

module.exports = function fractionToBitString(x) {
	var str = '';
	if (x === 0) {
		return str;
	}
	var j = MAX_ITER;

	var y;
	
	for (var i = 0; i < MAX_ITER; i += 1) {
		y = x * 2;
		if (y >= 1) {
			x = y - 1; 
			str += '1';
			if (j === MAX_ITER) {
				j = i; 
			}
		} else {
			x = y; 
			str += '0';
		}
		
		if (y === 1 || i - j > maxBits) {
			return str;
		}
	}
	return str;
};
